const P = window.__rzn_params || {};
const mode = String(P.mode || 'keyword').toLowerCase();
const country = String(P.country || 'US').toUpperCase();
const query = String(P.query || '');
// privacy-preserving: decline optional cookies if a consent dialog is present
try {
  const decline = Array.from(document.querySelectorAll('[role="button"],button'))
    .find(b => /decline optional cookies|only allow essential|decline/i.test(b.textContent || ''));
  if (decline) decline.click();
} catch (e) {}
if (mode !== 'advertiser') return { navigated: false, page_id: null };

let pageId = String(P.page_id || '').replace(/[^0-9]/g, '');
if (!pageId) {
  // Resolve the searched advertiser's Facebook Page id: pick the ad card whose
  // advertiser name matches the query, then read the page_id nearest that card's
  // Library ID in the page data (both live in the same ad JSON node).
  const cut = (s, n) => { s = (s || '').replace(/\s+/g, ' ').trim(); return s.length > n ? s.slice(0, n) : s; };
  const oneLib = (el) => ((el.innerText || '').match(/Library ID/gi) || []).length === 1;
  const labels = Array.from(document.querySelectorAll('*')).filter(e =>
    Array.from(e.childNodes || []).some(n => n.nodeType === 3 && /Library ID/i.test(n.textContent || '')));
  const seen = new Set(); const cards = [];
  for (const lab of labels) { let c = lab; while (c.parentElement && oneLib(c.parentElement)) c = c.parentElement; if (!seen.has(c)) { seen.add(c); cards.push(c); } }
  const mini = cards.map(card => {
    const txt = card.innerText || '';
    const id = (txt.match(/Library ID:?\s*(\d{5,})/) || [])[1] || null;
    const sp = txt.split(/\bSponsored\b/); let adv = null;
    if (sp.length > 1) { const bl = sp[0].trim().split('\n').filter(Boolean); adv = cut(bl[bl.length - 1], 60); }
    return { id: id, adv: adv };
  }).filter(c => c.id && c.adv);
  const ql = query.toLowerCase();
  const match = mini.find(c => c.adv.toLowerCase() === ql)
    || mini.find(c => c.adv.toLowerCase().indexOf(ql) >= 0)
    || mini.find(c => ql.indexOf(c.adv.toLowerCase()) >= 0);
  if (match) {
    const html = document.documentElement.innerHTML;
    let idx = html.indexOf('"' + match.id + '"'); if (idx < 0) idx = html.indexOf(match.id);
    if (idx >= 0) {
      const W = 8000; const w = html.slice(Math.max(0, idx - W), idx + W); const rel = Math.min(idx, W);
      let best = null, bd = 1e9; const re = /page_id["\\]{0,2}\s*:\s*["\\]{0,2}(\d{5,})/g; let mm;
      while ((mm = re.exec(w)) !== null) { const d = Math.abs(mm.index - rel); if (d < bd) { bd = d; best = mm[1]; } }
      pageId = best || '';
    }
  }
}
if (pageId) {
  location.assign('https://www.facebook.com/ads/library/?active_status=active&ad_type=all&country=' + encodeURIComponent(country) + '&view_all_page_id=' + pageId + '&media_type=all');
  return { navigated: true, page_id: pageId };
}
return { navigated: false, page_id: null, warning: 'advertiser_unresolved' };

const P = window.__rzn_params || {};
const mode = String(P.mode || 'keyword').toLowerCase();
const country = String(P.country || 'US').toUpperCase();
const query = String(P.query || '');
let cap = parseInt(P.cap, 10);
if (!Number.isFinite(cap) || cap < 1) cap = 30;
if (cap > 300) cap = 300;

const sleep = (ms) => new Promise(r => setTimeout(r, ms));
const cut = (s, n) => { s = (s || '').replace(/\s+/g, ' ').trim(); return s.length > n ? s.slice(0, n) : s; };
const oneLib = (el) => ((el.innerText || '').match(/Library ID/gi) || []).length === 1;
const toISO = (raw) => { if (!raw) return null; const d = new Date(raw); return isNaN(d.getTime()) ? null : d.toISOString().slice(0, 10); };
const findCards = () => {
  const labels = Array.from(document.querySelectorAll('*')).filter(e =>
    Array.from(e.childNodes || []).some(n => n.nodeType === 3 && /Library ID/i.test(n.textContent || '')));
  const seen = new Set(); const cards = [];
  for (const lab of labels) { let c = lab; while (c.parentElement && oneLib(c.parentElement)) c = c.parentElement; if (!seen.has(c)) { seen.add(c); cards.push(c); } }
  return cards;
};
const preview = (card) => {
  const hit = Array.from(card.querySelectorAll('img')).map(i => i.getAttribute('src') || '')
    .find(s => /scontent|fbcdn/i.test(s) && !/s60x60|p60x60|static\.xx/i.test(s));
  return hit || null;
};
const parse = (card) => {
  const txt = card.innerText || '';
  const id = (txt.match(/Library ID:?\s*(\d{5,})/) || [])[1] || null;
  if (!id) return null;
  const status = /\bInactive\b/i.test(txt) ? 'inactive' : (/\bActive\b/i.test(txt) ? 'active' : null);
  const sr = (txt.match(/Started running on\s+(\d{1,2}\s+\w{3,}\s+\d{4})/) || [])[1] || null;
  const iso = toISO(sr);
  const sp = txt.split(/\bSponsored\b/); let adv = null, copy = null;
  if (sp.length > 1) { const bl = sp[0].trim().split('\n').filter(Boolean); adv = cut(bl[bl.length - 1], 80); copy = cut(sp[1], 2000) || null; }
  const vid = card.querySelector('video');
  const media = vid ? 'video' : (card.querySelector('img') ? 'image' : 'text');
  const prev = preview(card);
  const asset_url = vid ? (vid.getAttribute('src') || vid.currentSrc || prev) : prev;
  const asset_ext = vid ? 'mp4' : 'jpg';
  return { id: id, advertiser_id: null, advertiser_name: adv, media_type: media, first_shown: iso, started_at: iso, last_shown: null, copy: copy, url: 'https://www.facebook.com/ads/library/?id=' + id, preview_url: prev, asset_url: asset_url, asset_ext: asset_ext };
};

const collected = new Map();
// Add a newly-seen ad, or upgrade a previously-captured image asset to the real
// video URL once the lazily-mounted <video> element exposes its src.
const ingest = () => {
  for (const card of findCards()) {
    const r = parse(card);
    if (!r) continue;
    const ex = collected.get(r.id);
    if (!ex) { collected.set(r.id, r); }
    else if (r.asset_ext === 'mp4' && ex.asset_ext !== 'mp4') {
      ex.asset_url = r.asset_url; ex.asset_ext = 'mp4'; ex.media_type = 'video';
    }
  }
};
let stagnant = 0, brokeOnCap = false, lastY = -1;
// Gradual scroll (~one viewport/step) so each card passes through the mount zone
// while we ingest; a fast jump-to-bottom skips lazily-loaded <video> srcs.
for (let iter = 0; iter < 150 && stagnant < 5; iter++) {
  ingest();
  if (collected.size >= cap) { brokeOnCap = true; break; }
  const before = collected.size;
  window.scrollBy(0, Math.floor(window.innerHeight * 0.8));
  await sleep(900);
  const y = window.scrollY;
  if (collected.size === before && y === lastY) stagnant++; else stagnant = 0;
  lastY = y;
}
ingest();

let ads = Array.from(collected.values());
const truncated = brokeOnCap;
if (ads.length > cap) ads = ads.slice(0, cap);
const pid = (location.href.match(/view_all_page_id=(\d+)/) || [])[1] || null;
if (pid) ads.forEach(a => { a.advertiser_id = pid; });
const q = (mode === 'advertiser')
  ? { advertiser: query || null, advertiser_id: pid, region: country }
  : { keyword: query || null, region: country };
// Asset refs for `--download-dir` capture (ADI-T-0002): one per ad with a media URL.
const attachment_urls = ads
  .filter(a => a.asset_url)
  .map(a => ({ url: a.asset_url, filename: a.id + '.' + a.asset_ext }));
return { source: 'meta_ad_library', query: q, mode: mode, cap: cap, count: ads.length, truncated: truncated, advertiser_name: (mode === 'advertiser' && ads[0]) ? ads[0].advertiser_name : null, advertiser_id: pid, ads: ads, attachment_urls: attachment_urls };
